#include <cstdio>

#include <cstring>

#include <queue>

#define MAX_N 100000

using namespace std;

typedef long long int ll;

typedef pair<ll, int> PLI;





int N;

priority_queue<PLI> q;

ll ans[MAX_N];



int main() {



  PLI p;

  ll a, cnt;

  int min_i;



  scanf("%d", &N);

  q.push(PLI(0, -1));

  for (int i = 0; i < N; i++) {

    scanf("%lld", &a);

    q.push(PLI(a, i));

  }

  memset(ans, 0, sizeof(ans));



  min_i = N;

  cnt = 0;

  while (q.size() > 1) {

    p = q.top(); q.pop();

    min_i = min(min_i, p.second);

    ans[min_i] += (p.first - q.top().first) * (cnt + 1);

    cnt++;

  }



  for (int i = 0; i < N; i++) {

    printf("%lld\n", ans[i]);

  }



  return 0;



}

